import{_ as a,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Baja tensión","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/distribution/low-voltage.md","filePath":"es/power-systems/distribution/low-voltage.md"}'),n={name:"es/power-systems/distribution/low-voltage.md"};function r(t,e,l,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="baja-tension" tabindex="-1">Baja tensión <a class="header-anchor" href="#baja-tension" aria-label="Permalink to &quot;Baja tensión&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los sistemas de baja tensión (LV) se utilizan para distribuir energía eléctrica a niveles adecuados para el uso directo de la mayoría del equipo industrial.</p><p>En entornos industriales, la baja tensión típicamente se refiere a sistemas de hasta 1000 V CA.</p><p>Estos sistemas son la etapa final de distribución de energía antes de que la energía llegue a cargas como motores, tableros de control, iluminación y sistemas auxiliares.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los sistemas de baja tensión es:</p><ul><li>Proporcionar niveles de voltaje utilizables para el equipo industrial</li><li>Permitir operación y mantenimiento seguros</li><li>Soportar la protección y el control de cargas eléctricas</li><li>Distribuir energía de manera eficiente dentro de áreas localizadas</li></ul><p>La baja tensión es donde la energía se consume realmente y se convierte en funciones mecánicas, térmicas o de control.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La energía eléctrica se reduce desde media tensión mediante transformadores a niveles de baja tensión.</p><p>Una vez en baja tensión, la energía se distribuye a través de:</p><ul><li>Tableros de distribución y paneles de distribución</li><li>Barras colectoras y alimentadores</li><li>Circuitos derivados que alimentan cargas individuales</li></ul><p>Los dispositivos de protección, como interruptores automáticos y fusibles, se instalan para detectar fallas y desconectar los circuitos afectados.</p><p>Las cargas se conectan a través de circuitos dedicados dimensionados según la demanda de corriente y las condiciones de instalación.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los sistemas de baja tensión se utilizan en:</p><ul><li>Alimentación de motores para bombas, transportadores, compresores y ventiladores</li><li>Tableros de control y sistemas de automatización</li><li>Sistemas de iluminación y servicios auxiliares</li><li>Equipo de calefacción y de proceso</li><li>Infraestructura comercial y de edificios dentro de sitios industriales</li></ul><p>La mayoría del equipo de usuario final opera a niveles de baja tensión.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Niveles de voltaje</strong><br> Los niveles industriales comunes incluyen 120 V, 230 V, 400 V y 480 V según la región y la aplicación</p></li><li><p><strong>Niveles de corriente</strong><br> Un voltaje más bajo resulta en mayor corriente para la misma potencia, afectando el dimensionamiento de conductores y las pérdidas</p></li><li><p><strong>Dispositivos de protección</strong><br> La selección adecuada de interruptores automáticos y fusibles es crítica para la seguridad y la protección del equipo</p></li><li><p><strong>Capacidad de cortocircuito</strong><br> El equipo debe estar dimensionado para manejar la corriente de falla disponible en el punto de instalación</p></li><li><p><strong>Caída de voltaje</strong><br> Recorridos largos de cable pueden reducir el voltaje en la carga, afectando el desempeño</p></li><li><p><strong>Entorno de instalación</strong><br> La temperatura, la agrupación de cables y el enrutamiento impactan la capacidad de conducción de corriente</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los sistemas de baja tensión son más accesibles, lo que aumenta la exposición a la interacción humana y el riesgo</li><li>Los niveles altos de corriente requieren un diseño cuidadoso para evitar sobrecalentamiento y pérdidas excesivas</li><li>El diseño deficiente de paneles y las prácticas de cableado son fuentes comunes de fallas</li><li>La estandarización de niveles de voltaje simplifica el mantenimiento y el reemplazo de equipo</li></ul>',23)])])}const b=a(n,[["render",r]]);export{m as __pageData,b as default};
